import axios from 'axios';

// All requests go through the API Gateway on port 8085
const api = axios.create({
  baseURL: 'http://localhost:8085',
});

// Attach JWT token to every request automatically
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Handle 401 globally
api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      const url = err.config?.url || '';
      if (!url.includes('/auth/login') && !url.includes('/auth/register')) {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        window.location.href = '/login';
      }
    }
    return Promise.reject(err);
  }
);

// AUTH API - matches AuthController exactly
export const authAPI = {
  register: (data) =>
    api.post('/auth/register', data),

  login: (data) =>
    api.post('/auth/login', data),

  // Backend uses @RequestParam - must be query params NOT body
  verifyOtp: (email, otp) =>
    api.post('/auth/verify?email=' + encodeURIComponent(email) + '&otp=' + encodeURIComponent(otp)),

  // Backend uses @RequestParam
  resendOtp: (email) =>
    api.post('/auth/resend?email=' + encodeURIComponent(email)),

  // Backend endpoint is /auth/forgot NOT /auth/forgot-password
  // Backend uses @RequestParam email NOT request body
  forgotPassword: (email) =>
    api.post('/auth/forgot?email=' + encodeURIComponent(email)),

  // Backend uses @RequestBody { email, otp, newPassword }
  resetPassword: (data) =>
    api.post('/auth/reset', data),

  // Token auto-attached by request interceptor above
  logout: () =>
    api.post('/auth/logout'),
};

// BOOKS API - matches BookController exactly
export const booksAPI = {
  getAll:   ()         => api.get('/books'),
  add:      (data)     => api.post('/books', data),
  getById:  (id)       => api.get('/books/' + id),
  update:   (id, data) => api.put('/books/' + id, data),
  delete:   (id)       => api.delete('/books/' + id),
  // Legacy aliases kept for compatibility
  getBooks: (params)   => api.get('/books', { params }),
  getBook:  (id)       => api.get('/books/' + id),
};

// CART API
export const cartAPI = {
  getCart:        (userId)               => api.get('/cart/' + userId),
  addItem:        (userId, item)         => api.post('/cart/' + userId + '/items', item),
  removeItem:     (userId, itemId)       => api.delete('/cart/' + userId + '/items/' + itemId),
  updateQuantity: (userId, itemId, data) => api.put('/cart/' + userId + '/items/' + itemId, data),
  clearCart:      (userId)               => api.delete('/cart/' + userId),
};

export default api;
